create extension if not exists "uuid-ossp";
create table public.roles (id uuid primary key default uuid_generate_v4(), name text unique not null check(name in ('owner','admin','employee')));
create table public.users (id uuid primary key references auth.users on delete cascade, role_id uuid references public.roles, full_name text, created_at timestamptz default now());
create table public.categories (id uuid primary key default uuid_generate_v4(), name text not null, created_at timestamptz default now());
create table public.brands (id uuid primary key default uuid_generate_v4(), name text not null unique);
create table public.suppliers (id uuid primary key default uuid_generate_v4(), name text not null, phone text, email text, company text, address text, balance numeric default 0, created_at timestamptz default now());
create table public.customers (id uuid primary key default uuid_generate_v4(), name text not null, phone text unique, city text, address text, facebook text, instagram text, notes text, balance numeric default 0, created_at timestamptz default now());
create table public.products (id uuid primary key default uuid_generate_v4(), name text not null, sku text unique, barcode text unique, category_id uuid references public.categories, brand_id uuid references public.brands, supplier_id uuid references public.suppliers, description text, images jsonb default '[]', purchase_price numeric default 0, price numeric not null default 0, wholesale_price numeric default 0, status text default 'active', created_at timestamptz default now());
create table public.product_variants (id uuid primary key default uuid_generate_v4(), product_id uuid not null references public.products on delete cascade, color text, size text, barcode text unique, selling_price numeric, purchase_price numeric, stock_quantity integer not null default 0, minimum_stock integer not null default 0);
create table public.sales (id uuid primary key default uuid_generate_v4(), number text unique not null, customer_id uuid references public.customers, total numeric not null, discount numeric default 0, tax numeric default 0, shipping numeric default 0, payment_method text, status text default 'completed', created_at timestamptz default now());
create table public.sale_items (id uuid primary key default uuid_generate_v4(), sale_id uuid not null references public.sales on delete cascade, variant_id uuid references public.product_variants, quantity integer not null, unit_price numeric not null, cost_price numeric default 0);
create table public.inventory_movements (id uuid primary key default uuid_generate_v4(), variant_id uuid not null references public.product_variants, type text not null check(type in ('purchase','sale','adjustment','return','damaged','transfer')), quantity integer not null, reference_id uuid, created_at timestamptz default now());
create table public.expenses (id uuid primary key default uuid_generate_v4(), category text not null, amount numeric not null, note text, expense_date date default current_date, created_at timestamptz default now());
create table public.payments (id uuid primary key default uuid_generate_v4(), customer_id uuid references public.customers, supplier_id uuid references public.suppliers, amount numeric not null, method text, paid_at timestamptz default now());
create table public.delivery_orders (id uuid primary key default uuid_generate_v4(), sale_id uuid references public.sales, status text default 'new', tracking_number text, shipping_price numeric default 0, cod numeric default 0, created_at timestamptz default now());
create table public.ozon_shipments (id uuid primary key default uuid_generate_v4(), delivery_order_id uuid references public.delivery_orders, payload jsonb, response jsonb, status text, created_at timestamptz default now());
create table public.settings (id uuid primary key default uuid_generate_v4(), key text unique not null, value jsonb, updated_at timestamptz default now());
create table public.activity_logs (id uuid primary key default uuid_generate_v4(), user_id uuid references public.users, action text not null, entity text, entity_id uuid, created_at timestamptz default now());
alter table public.roles enable row level security; alter table public.users enable row level security; alter table public.categories enable row level security; alter table public.brands enable row level security; alter table public.suppliers enable row level security; alter table public.customers enable row level security; alter table public.products enable row level security; alter table public.product_variants enable row level security; alter table public.sales enable row level security; alter table public.sale_items enable row level security; alter table public.inventory_movements enable row level security; alter table public.expenses enable row level security; alter table public.payments enable row level security; alter table public.delivery_orders enable row level security; alter table public.ozon_shipments enable row level security; alter table public.settings enable row level security; alter table public.activity_logs enable row level security;
create policy "authenticated full access roles" on public.roles for all to authenticated using (true) with check (true);
