create policy "authenticated full access customers" on public.customers for all to authenticated using (true) with check (true);
create policy "authenticated full access products" on public.products for all to authenticated using (true) with check (true);
create policy "authenticated full access variants" on public.product_variants for all to authenticated using (true) with check (true);
create policy "authenticated full access sales" on public.sales for all to authenticated using (true) with check (true);
create policy "authenticated full access sale items" on public.sale_items for all to authenticated using (true) with check (true);
create policy "authenticated full access movements" on public.inventory_movements for all to authenticated using (true) with check (true);
create policy "authenticated full access expenses" on public.expenses for all to authenticated using (true) with check (true);
